import React, { useState, lazy, Suspense } from "react";
import "./styles/global.css";

import Navbar      from "./components/layout/Navbar";
import Footer      from "./components/layout/Footer";
import Chatbot     from "./components/layout/Chatbot";
import Home        from "./components/pages/Home";

// Lazy-loaded pages: each only downloads its JS when the visitor
// actually navigates there, instead of all pages loading upfront.
// Home stays eager since it's the first thing almost everyone sees.
const About      = lazy(() => import("./components/pages/About"));
const Services   = lazy(() => import("./components/pages/Services"));
const Careers    = lazy(() => import("./components/pages/Careers"));
const Contact    = lazy(() => import("./components/pages/Contact"));
const AdminPanel = lazy(() => import("./components/pages/AdminPanel"));

import useJobs        from "./hooks/useJobs";
import { useScroll, useChat } from "./hooks/useHooks";

// Minimal, brand-colored loading indicator shown briefly while a
// lazy page chunk downloads (usually well under a second on a good
// connection, a bit longer on slow mobile data).
function PageLoader() {
  return (
    <div style={{ minHeight: "60vh", display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div style={{ width: 38, height: 38, borderRadius: "50%", border: "3.5px solid #E8EEFF", borderTopColor: "#0284C7", animation: "spin 0.7s linear infinite" }} />
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

export default function App() {
  const [page, setPage]         = useState("Home");
  const [svcId, setSvcId]       = useState(null);
  const [applyJob, setApplyJob] = useState(null);   // { title, dept }
  const [adminOpen, setAdminOpen] = useState(false);

  const scrolled = useScroll();
  // IMPORTANT: setJobs must come from useJobs() and be passed to AdminPanel,
  // since AdminPanel's add/delete/edit/toggle actions call setJobs directly.
  const { jobs, setJobs, activeJobs, addJob, updateJob, deleteJob, toggleHot, toggleActive } = useJobs();
  const chat = useChat(activeJobs.length);

  /* ── Navigation helpers ── */
  const goTo = (pg) => {
    setPage(pg);
    if (pg !== "Services") setSvcId(null);
    if (pg !== "Careers")  setApplyJob(null);
    window.scrollTo(0, 0);
  };

  const goService = (id) => {
    setPage("Services");
    setSvcId(id);
    window.scrollTo(0, 0);
  };

  const handleApply = (title, dept) => {
    setApplyJob({ title, dept });
    setPage("Careers");
    window.scrollTo(0, 0);
  };

  /* ── Page map ── */
  const renderPage = () => {
    switch (page) {
      case "Home":
        return <Home activeJobs={activeJobs} onNav={goTo} onApply={handleApply} onService={goService} />;
      case "About":
        return <About />;
      case "Services":
        return <Services activeSvc={svcId} onService={goService} onBack={() => setSvcId(null)} />;
      case "Careers":
        return <Careers activeJobs={activeJobs} initialJob={applyJob} />;
      case "Contact":
        return <Contact />;
      default:
        return <Home activeJobs={activeJobs} onNav={goTo} onApply={handleApply} onService={goService} />;
    }
  };

  return (
    <div style={{ minHeight: "100vh", background: "#F8FAFC" }}>

      {/* ── Navbar ── */}
      <Navbar currentPage={page} onNav={goTo} scrolled={scrolled} />

      {/* ── Page content ── */}
      <main><Suspense fallback={<PageLoader />}>{renderPage()}</Suspense></main>

      {/* ── Footer ── */}
      <Footer onNav={goTo} onService={goService} />

      {/* ── Chatbot ── */}
      <Chatbot
        msgs={chat.msgs}
        input={chat.input}
        setInput={chat.setInput}
        typing={chat.typing}
        open={chat.open}
        setOpen={chat.setOpen}
        sendMsg={chat.sendMsg}
        bottomRef={chat.bottomRef}
      />

      {/* ── Admin trigger button ── */}
      <button
        onClick={() => setAdminOpen(true)}
        title="Admin Panel"
        style={{
          position: "fixed", bottom: 26, left: 26, zIndex: 997,
          width: 42, height: 42, borderRadius: 11,
          background: "rgba(8,14,28,.82)", backdropFilter: "blur(8px)",
          border: "1px solid rgba(255,255,255,.08)",
          color: "rgba(255,255,255,.38)", cursor: "pointer",
          display: "flex", alignItems: "center", justifyContent: "center",
          transition: "all .2s",
        }}
        onMouseEnter={e => { e.currentTarget.style.background = "rgba(2,132,199,.88)"; e.currentTarget.style.color = "#fff"; }}
        onMouseLeave={e => { e.currentTarget.style.background = "rgba(8,14,28,.82)"; e.currentTarget.style.color = "rgba(255,255,255,.38)"; }}
      >
        <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <rect x="3" y="3" width="7" height="7" /><rect x="14" y="3" width="7" height="7" />
          <rect x="14" y="14" width="7" height="7" /><rect x="3" y="14" width="7" height="7" />
        </svg>
      </button>

      {/* ── Admin panel ── */}
      {adminOpen && (
        <Suspense fallback={<PageLoader />}>
          <AdminPanel
            jobs={jobs}
            setJobs={setJobs}
            onClose={() => setAdminOpen(false)}
            onAdd={addJob}
            onUpdate={updateJob}
            onDelete={deleteJob}
            onToggleHot={toggleHot}
            onToggleActive={toggleActive}
          />
        </Suspense>
      )}
    </div>
  );
}