import { useState, useEffect, useRef, useCallback } from "react";
import { WA_LINK } from "../data/constants";

// ── useScroll ──────────────────────────────────────────────────────────────
export function useScroll(threshold = 8) {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > threshold);
    window.addEventListener("scroll", fn, { passive: true });
    return () => window.removeEventListener("scroll", fn);
  }, [threshold]);
  return scrolled;
}

// ── useChat ────────────────────────────────────────────────────────────────
const INITIAL_MSGS = [
  {
    from: "bot",
    text: "Hello! 👋 Welcome to A-CONNEXION Tech International!\n\nEst. 2005 · 20+ Years · 3,000+ Placements\n\nHow can I help you today?",
    quick: ["View Openings", "IT Jobs", "Non-IT Jobs", "Contact Us"],
  },
];

export function useChat(activeJobCount) {
  const [msgs, setMsgs]     = useState(INITIAL_MSGS);
  const [input, setInput]   = useState("");
  const [typing, setTyping] = useState(false);
  const [open, setOpen]     = useState(false);
  const bottomRef           = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [msgs, typing]);

  const getBotReply = useCallback((q) => {
    const ql = q.toLowerCase();
    if (ql.includes("opening") || ql.includes("job") || ql.includes("vacancy"))
      return `We have ${activeJobCount} live openings!\n💻 IT roles & 👥 Non-IT roles\n\nGo to Careers page to apply!`;
    if (ql.includes("address") || ql.includes("location") || ql.includes("office"))
      return `📍 Arenja Arcade, Office 112, Sector 17, Vashi, Navi Mumbai 400704\n\n📞 +91 9869043500\n📧 info@aconnexion.in`;
    if (ql.includes("contact") || ql.includes("phone"))
      return `📞 +91 9869043500\n📞 +91 8897123500\n📧 info@aconnexion.in\n\nOr WhatsApp us at: ${WA_LINK}`;
    if (ql.includes("hello") || ql.includes("hi") || ql.includes("hey"))
      return `Hello! 👋 How can I help?\n• View Current Openings\n• IT Recruitment\n• Non-IT Recruitment\n• Payroll / Software / BPO`;
    return `Thank you! 😊\n\nFor quick response:\n📞 +91 9869043500\n📧 info@aconnexion.in\n💬 WhatsApp: ${WA_LINK}`;
  }, [activeJobCount]);

  const sendMsg = useCallback((text) => {
    const q = text || input.trim();
    if (!q) return;
    setMsgs(m => [...m, { from: "user", text: q }]);
    setInput("");
    setTyping(true);
    setTimeout(() => {
      setTyping(false);
      setMsgs(m => [...m, { from: "bot", text: getBotReply(q) }]);
    }, 650);
  }, [input, getBotReply]);

  return { msgs, input, setInput, typing, open, setOpen, sendMsg, bottomRef };
}
