// ── Mini Job Card ─────────────────────────────────────────────────────────
function MiniJobCard({ job, onApply, onNav }) {
  const [hov, setHov] = useState(false);
  const isIT  = job.dept === "IT";
  const color = isIT ? "#0284C7" : "#059669";
  const light = isIT ? "#EFF9FF" : "#ECFDF5";

  return (
    <div
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        background: "#fff",
        borderRadius: 14,
        border: `1.5px solid ${hov ? color : "#E8EEFF"}`,
        padding: "16px 20px",
        display: "flex", alignItems: "center", justifyContent: "space-between",
        gap: 14, flexWrap: "wrap",
        boxShadow: hov ? `0 8px 28px ${color}18` : "0 1px 8px rgba(0,0,0,0.04)",
        transition: "all 0.25s cubic-bezier(0.4,0,0.2,1)",
        transform: hov ? "translateX(4px)" : "none",
        cursor: "pointer",
        position: "relative", overflow: "hidden",
      }}
    >
      {/* Left color bar */}
      <div style={{ position: "absolute", left: 0, top: 0, bottom: 0, width: 3, background: hov ? color : "transparent", borderRadius: "14px 0 0 14px", transition: "all 0.25s" }} />

      <div style={{ display: "flex", alignItems: "center", gap: 12, flex: 1, minWidth: 0 }}>
        {/* Icon */}
        <div style={{ width: 38, height: 38, borderRadius: 10, background: hov ? color : light, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, transition: "all 0.25s" }}>
          {isIT ? <ITIcon size={18} color={hov ? "#fff" : color} /> : <NonITIcon size={18} color={hov ? "#fff" : color} />}
        </div>

        <div style={{ minWidth: 0 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 7, flexWrap: "wrap", marginBottom: 4 }}>
            <span style={{ fontWeight: 800, fontSize: 13.5, color: "#0F172A", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{job.title}</span>
            {job.hot && <span style={{ background: "#FFF7ED", color: "#EA580C", fontSize: 9, fontWeight: 900, padding: "2px 6px", borderRadius: 50, border: "1px solid #FED7AA", flexShrink: 0 }}>🔥 HOT</span>}
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
            <span style={{ display: "flex", alignItems: "center", gap: 3, fontSize: 11.5, color: "#64748B" }}><PinIcon /> {job.loc}</span>
            <span style={{ display: "flex", alignItems: "center", gap: 3, fontSize: 11.5, color: "#64748B" }}><ClockIcon /> {job.exp}</span>
            <span style={{ background: light, color, fontSize: 9.5, fontWeight: 700, padding: "2px 8px", borderRadius: 50, border: `1px solid ${color}22` }}>{job.type}</span>
          </div>
        </div>
      </div>

      <button
        onClick={() => { onApply(job.title, job.dept); onNav("Careers"); }}
        style={{ background: hov ? color : "#F8FAFF", color: hov ? "#fff" : color, border: `1.5px solid ${color}`, borderRadius: 50, padding: "8px 18px", fontSize: 12, fontWeight: 800, cursor: "pointer", fontFamily: "'Plus Jakarta Sans',sans-serif", transition: "all 0.25s", flexShrink: 0, whiteSpace: "nowrap" }}
      >
        Apply →
      </button>
    </div>
  );
}

