import React from "react";

export default function Chatbot({ msgs, input, setInput, typing, open, setOpen, sendMsg, bottomRef }) {
  return (
    <div style={{ position: "fixed", bottom: 26, right: 26, zIndex: 998 }}>
      {open && (
        <div style={{ position: "absolute", bottom: 70, right: 0, width: "clamp(296px,90vw,348px)", background: "#fff", borderRadius: 24, boxShadow: "0 16px 56px rgba(0,0,0,.14)", border: "1px solid #EEF2FF", overflow: "hidden" }}>

          {/* Header */}
          <div style={{ background: "linear-gradient(135deg,#0284C7,#075985)", padding: "15px 19px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 11 }}>
              <div style={{ width: 38, height: 38, background: "rgba(255,255,255,.16)", borderRadius: 12, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 17 }}>🎯</div>
              <div>
                <div style={{ color: "#fff", fontWeight: 900, fontSize: 13 }}>A-CONNEXION Support</div>
                <div style={{ color: "rgba(186,230,253,.75)", fontSize: 10.5, marginTop: 2, fontWeight: 400 }}>🟢 Online · Responds in minutes</div>
              </div>
            </div>
            <button onClick={() => setOpen(false)} style={{ background: "rgba(255,255,255,.1)", border: "none", color: "#fff", cursor: "pointer", width: 28, height: 28, borderRadius: 8, fontSize: 13, fontFamily: "'Plus Jakarta Sans',sans-serif", fontWeight: 900 }}>✕</button>
          </div>

          {/* Messages */}
          <div style={{ maxHeight: 290, overflowY: "auto", padding: 13, display: "flex", flexDirection: "column", gap: 9, background: "#F8FAFC" }}>
            {msgs.map((m, i) => (
              <div key={i} style={{ alignSelf: m.from === "user" ? "flex-end" : "flex-start", maxWidth: "88%" }}>
                <div style={{
                  background: m.from === "user" ? "linear-gradient(135deg,#0284C7,#075985)" : "#fff",
                  color: m.from === "user" ? "#fff" : "#0F172A",
                  border: m.from === "bot" ? "1px solid #EEF2FF" : "none",
                  borderRadius: m.from === "user" ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
                  padding: "10px 14px", fontSize: 12.5, lineHeight: 1.65,
                  whiteSpace: "pre-wrap", fontWeight: m.from === "user" ? 600 : 400,
                }}>
                  {m.text}
                </div>
                {m.quick && (
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 5, marginTop: 6 }}>
                    {m.quick.map(q => (
                      <button key={q} onClick={() => sendMsg(q)} style={{ background: "#fff", border: "1px solid #EEF2FF", color: "#0284C7", padding: "5px 11px", borderRadius: 50, cursor: "pointer", fontWeight: 700, fontSize: 10.5, fontFamily: "'Plus Jakarta Sans',sans-serif" }}>
                        {q}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            ))}
            {typing && (
              <div style={{ alignSelf: "flex-start", background: "#fff", border: "1px solid #EEF2FF", borderRadius: "18px 18px 18px 4px", padding: "10px 14px", display: "flex", gap: 4 }}>
                {[0, 0.15, 0.3].map((d, i) => (
                  <div key={i} style={{ width: 6, height: 6, borderRadius: "50%", background: "#38BDF8", animation: `bounce 1s ${d}s infinite` }} />
                ))}
              </div>
            )}
            <div ref={bottomRef} />
          </div>

          {/* Input */}
          <div style={{ padding: "10px 12px", borderTop: "1px solid #EEF2FF", display: "flex", gap: 7, background: "#fff" }}>
            <input
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => e.key === "Enter" && sendMsg()}
              placeholder="Type your message..."
              style={{ flex: 1, background: "#F8FAFC", border: "1.5px solid #EEF2FF", color: "#0F172A", padding: "10px 14px", borderRadius: 50, fontSize: 12.5, outline: "none", fontFamily: "'Plus Jakarta Sans',sans-serif" }}
            />
            <button onClick={() => sendMsg()} style={{ background: "linear-gradient(135deg,#0284C7,#075985)", color: "#fff", border: "none", borderRadius: "50%", width: 40, height: 40, cursor: "pointer", fontSize: 17, flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center" }}>→</button>
          </div>
        </div>
      )}

      {/* Toggle button */}
      <button onClick={() => setOpen(o => !o)} style={{ width: 58, height: 58, borderRadius: "50%", background: open ? "#fff" : "linear-gradient(135deg,#0284C7,#075985)", border: open ? "2px solid #0284C7" : "none", color: open ? "#0284C7" : "#fff", cursor: "pointer", fontSize: 24, boxShadow: "0 4px 24px rgba(2,132,199,.38)", display: "flex", alignItems: "center", justifyContent: "center", transition: "all .22s" }}>
        {open ? "✕" : "💬"}
      </button>
    </div>
  );
}
