import { useState, useCallback } from "react";
import DEFAULT_JOBS from "../data/jobs";

const STORAGE_KEY = "acjobs_v2";

function load() {
  try {
    const s = localStorage.getItem(STORAGE_KEY);
    if (s) {
      const parsed = JSON.parse(s);
      if (Array.isArray(parsed) && parsed.length > 0) return parsed;
    }
  } catch (_) {}
  return DEFAULT_JOBS;
}

function save(jobs) {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(jobs)); } catch (_) {}
}

export default function useJobs() {
  const [jobs, setJobsState] = useState(() => load());

  const setJobs = useCallback((next) => {
    const updated = typeof next === "function" ? next(jobs) : next;
    setJobsState(updated);
    save(updated);
  }, [jobs]);

  const addJob = useCallback((job) => {
    const id = Math.max(0, ...jobs.map(j => j.id)) + 1;
    setJobs(prev => [...prev, { ...job, id, active: true }]);
  }, [jobs, setJobs]);

  const updateJob = useCallback((id, changes) => {
    setJobs(prev => prev.map(j => j.id === id ? { ...j, ...changes } : j));
  }, [setJobs]);

  const deleteJob = useCallback((id) => {
    setJobs(prev => prev.filter(j => j.id !== id));
  }, [setJobs]);

  const toggleHot = useCallback((id) => {
    setJobs(prev => prev.map(j => j.id === id ? { ...j, hot: !j.hot } : j));
  }, [setJobs]);

  const toggleActive = useCallback((id) => {
    setJobs(prev => prev.map(j => j.id === id ? { ...j, active: j.active === false ? true : false } : j));
  }, [setJobs]);

  const activeJobs = jobs.filter(j => j.active !== false);

  return { jobs, activeJobs, addJob, updateJob, deleteJob, toggleHot, toggleActive, setJobs };
}
