import React, { useState, useEffect } from "react";
import { NAV_ITEMS, WA_LINK } from "../../data/constants";
import Logo from "../ui/Logo";

export default function Navbar({ currentPage, onNav, scrolled }) {
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    const close = () => window.innerWidth > 900 && setMobileOpen(false);
    window.addEventListener("resize", close);
    return () => window.removeEventListener("resize", close);
  }, []);

  useEffect(() => {
    document.body.style.overflow = mobileOpen ? "hidden" : "";
    return () => { document.body.style.overflow = ""; };
  }, [mobileOpen]);

  const handleNav = (page) => {
    onNav(page);
    setMobileOpen(false);
  };

  return (
    <>
      <style>{`
        @media (max-width: 900px) {
          .nav-phone { display: none !important; }
          .nav-wa    { display: none !important; }
          .desk-nav  { display: none !important; }
        }
        @media (min-width: 901px) {
          .hamburger-btn { display: none !important; }
        }
      `}</style>

      <header style={{
        position: "fixed", top: 0, left: 0, right: 0, zIndex: 1000,
        transition: "box-shadow .3s",
        boxShadow: scrolled ? "0 2px 28px rgba(2,132,199,.14)" : "none",
      }}>

        {/* ── Top Bar ── */}
        <div style={{ background: "#fff", borderBottom: "1.5px solid #EEF2FF" }}>
          <div style={{
            maxWidth: 1400, margin: "0 auto",
            padding: "0 8px 0 clamp(10px,3vw,48px)",
            display: "flex", alignItems: "center", justifyContent: "space-between",
            height: "clamp(72px,9vw,130px)",
            boxSizing: "border-box",
          }}>

            {/* Logo */}
            <Logo onClick={() => handleNav("Home")} />

            {/* Right side */}
            <div style={{
              display: "flex", alignItems: "center",
              gap: 8, flexShrink: 0,
            }}>

              {/* Phone — desktop only */}
              <a href="tel:+919869043500" className="nav-phone"
                style={{ textDecoration: "none", color: "#334155", fontWeight: 700, fontSize: 13, display: "flex", alignItems: "center", gap: 6 }}>
                📞 +91 9869043500
              </a>

              {/* WhatsApp — desktop only */}
              <a href={WA_LINK} target="_blank" rel="noreferrer" className="nav-wa" style={{ textDecoration: "none" }}>
                <button className="btn-whatsapp" style={{ padding: "9px 18px", fontSize: 13 }}>
                  💬 WhatsApp
                </button>
              </a>

              {/* Hamburger — mobile only */}
              <button
                className="hamburger-btn"
                onClick={() => setMobileOpen(o => !o)}
                aria-label={mobileOpen ? "Close menu" : "Open menu"}
                style={{
                  display: "flex", flexDirection: "column",
                  justifyContent: "center", alignItems: "center",
                  gap: 5, width: 46, height: 46, minWidth: 46,
                  background: "linear-gradient(135deg,#0284C7,#0369A1)",
                  border: "none", borderRadius: 12, cursor: "pointer",
                  padding: 0, flexShrink: 0,
                  boxShadow: "0 4px 14px rgba(2,132,199,.35)",
                }}
              >
                <span style={{ display: "block", width: 20, height: 2.5, background: "#fff", borderRadius: 2, transition: "all .28s", transform: mobileOpen ? "rotate(45deg) translate(5px,5px)" : "none" }} />
                <span style={{ display: "block", width: 20, height: 2.5, background: "#fff", borderRadius: 2, transition: "all .28s", opacity: mobileOpen ? 0 : 1 }} />
                <span style={{ display: "block", width: 20, height: 2.5, background: "#fff", borderRadius: 2, transition: "all .28s", transform: mobileOpen ? "rotate(-45deg) translate(5px,-5px)" : "none" }} />
              </button>

            </div>
          </div>
        </div>

        {/* ── Desktop Nav Bar ── */}
        <div className="desk-nav" style={{ background: "linear-gradient(135deg,#0284C7,#0369A1)" }}>
          <div style={{ maxWidth: 1400, margin: "0 auto", padding: "0 clamp(10px,3vw,44px)", display: "flex", alignItems: "center" }}>
            {NAV_ITEMS.map(n => (
              <button key={n} className={"nav-link" + (currentPage === n ? " active" : "")} onClick={() => handleNav(n)} style={{ position: "relative" }}>
                {n}
                {currentPage === n && (
                  <span style={{ position: "absolute", bottom: 4, left: "50%", transform: "translateX(-50%)", width: 4, height: 4, borderRadius: "50%", background: "#7DD3FC" }} />
                )}
              </button>
            ))}
            <div style={{ flex: 1 }} />
            <button onClick={() => handleNav("Contact")}
              style={{ background: "#fff", color: "#0284C7", border: "none", borderRadius: 8, padding: "9px 22px", fontSize: 11.5, fontWeight: 900, cursor: "pointer", fontFamily: "'Plus Jakarta Sans',sans-serif", letterSpacing: 0.8, textTransform: "uppercase", transition: "all .2s", boxShadow: "0 2px 8px rgba(0,0,0,0.1)" }}
              onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-1px)"; e.currentTarget.style.boxShadow = "0 4px 16px rgba(0,0,0,0.15)"; }}
              onMouseLeave={e => { e.currentTarget.style.transform = "none"; e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.1)"; }}>
              🚀 Hire Talent
            </button>
          </div>
        </div>

        {/* ── Mobile Overlay ── */}
        {mobileOpen && (
          <div onClick={() => setMobileOpen(false)}
            style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.35)", zIndex: -1, backdropFilter: "blur(2px)" }} />
        )}

        {/* ── Mobile Menu ── */}
        <div className={"mob-menu" + (mobileOpen ? " open" : "")}>
          <div style={{ background: "#fff", borderBottom: "3px solid #0284C7", boxShadow: "0 12px 40px rgba(2,132,199,.15)" }}>
            {NAV_ITEMS.map((n, i) => (
              <button key={n} onClick={() => handleNav(n)}
                style={{ display: "flex", alignItems: "center", justifyContent: "space-between", width: "100%", textAlign: "left", padding: "15px 24px", background: currentPage === n ? "#F0F9FF" : "transparent", border: "none", borderLeft: "4px solid " + (currentPage === n ? "#0284C7" : "transparent"), borderBottom: i < NAV_ITEMS.length - 1 ? "1px solid #F1F5F9" : "none", color: currentPage === n ? "#0284C7" : "#334155", fontWeight: 800, fontSize: 13, cursor: "pointer", fontFamily: "'Plus Jakarta Sans',sans-serif", letterSpacing: 1.2, textTransform: "uppercase", transition: "all .15s" }}
                onMouseEnter={e => { if (currentPage !== n) e.currentTarget.style.background = "#F8FAFC"; }}
                onMouseLeave={e => { if (currentPage !== n) e.currentTarget.style.background = "transparent"; }}>
                <span>{n}</span>
                {currentPage === n && <span style={{ fontSize: 10, color: "#0284C7", fontWeight: 900 }}>●</span>}
              </button>
            ))}
            <div style={{ padding: "14px 20px 18px", borderTop: "1px solid #EEF2FF", display: "flex", gap: 10, flexWrap: "wrap", background: "#FAFBFF" }}>
              <a href="tel:+919869043500" style={{ textDecoration: "none", flex: 1 }}>
                <button className="btn-primary" style={{ fontSize: 13, padding: "11px 18px", width: "100%", justifyContent: "center" }}>📞 Call Us</button>
              </a>
              <button className="btn-whatsapp" onClick={() => handleNav("Contact")} style={{ fontSize: 13, padding: "11px 18px", flex: 1, justifyContent: "center" }}>
                🚀 Hire Now
              </button>
            </div>
          </div>
        </div>

      </header>
    </>
  );
}