import React, { useState } from "react";
import { SERVICES } from "../../data/constants";
import SvcIcon from "../ui/SvcIcon";

const ICONS = {
  IT:       { emoji: "💻", bg: "linear-gradient(135deg,#0284C7,#0EA5E9)" },
  NonIT:    { emoji: "👥", bg: "linear-gradient(135deg,#059669,#10B981)" },
  Payroll:  { emoji: "📊", bg: "linear-gradient(135deg,#7C3AED,#A78BFA)" },
  Software: { emoji: "⚙️", bg: "linear-gradient(135deg,#DC2626,#F87171)" },
  BPO:      { emoji: "📞", bg: "linear-gradient(135deg,#0369A1,#38BDF8)" },
};

export default function ServicesSection({ onService }) {
  const [hovered, setHovered] = useState(null);

  return (
    <div style={{ background: "linear-gradient(180deg,#F8FAFF 0%,#EFF6FF 100%)", padding: "clamp(64px,8vw,100px) clamp(16px,4vw,48px)" }}>
      <div style={{ maxWidth: 1400, margin: "0 auto" }}>

        {/* Header */}
        <div style={{ textAlign: "center", marginBottom: 64 }}>
          <div style={{ display: "inline-flex", alignItems: "center", gap: 8, background: "linear-gradient(135deg,#EFF9FF,#E0F2FE)", border: "1px solid #BAE6FD", borderRadius: 50, padding: "6px 20px", marginBottom: 18 }}>
            <span style={{ fontSize: 14 }}>⚡</span>
            <span style={{ fontSize: 10, fontWeight: 900, letterSpacing: 3, color: "#0284C7", textTransform: "uppercase" }}>What We Do</span>
          </div>
          <h2 style={{ fontSize: "clamp(28px,4vw,48px)", fontWeight: 900, color: "#0F172A", letterSpacing: -1.5, lineHeight: 1.15, marginBottom: 16 }}>
            Comprehensive<br />
            <span style={{ background: "linear-gradient(135deg,#0284C7,#38BDF8)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>Business Solutions</span>
          </h2>
          <p style={{ fontSize: "clamp(14px,1.5vw,17px)", color: "#64748B", maxWidth: 520, margin: "0 auto", lineHeight: 1.7, fontWeight: 400 }}>
            From talent acquisition to technology — we cover every aspect of your business growth.
          </p>
        </div>

        {/* Cards Grid */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(min(100%,260px),1fr))", gap: 24 }}>
          {SERVICES.map((s, i) => {
            const ic = ICONS[s.id] || { emoji: "🔷", bg: s.color };
            const isHovered = hovered === s.id;
            return (
              <div
                key={s.id}
                onClick={() => onService(s.id)}
                onMouseEnter={() => setHovered(s.id)}
                onMouseLeave={() => setHovered(null)}
                style={{
                  cursor: "pointer",
                  borderRadius: 24,
                  background: isHovered ? "#fff" : "#fff",
                  border: `1.5px solid ${isHovered ? s.color : "#E8EEFF"}`,
                  boxShadow: isHovered ? `0 20px 60px ${s.color}22` : "0 2px 20px rgba(0,0,0,0.05)",
                  padding: "32px 28px 28px",
                  transition: "all 0.3s cubic-bezier(0.4,0,0.2,1)",
                  transform: isHovered ? "translateY(-8px)" : "translateY(0)",
                  position: "relative",
                  overflow: "hidden",
                }}
              >
                {/* Top accent line */}
                <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 4, background: s.color, borderRadius: "24px 24px 0 0", opacity: isHovered ? 1 : 0, transition: "opacity 0.3s" }} />

                {/* Background number */}
                <div style={{ position: "absolute", right: 20, top: 16, fontSize: 72, fontWeight: 900, color: isHovered ? s.color : "#F1F5F9", opacity: 0.15, lineHeight: 1, transition: "all 0.3s", userSelect: "none" }}>
                  {String(i + 1).padStart(2, "0")}
                </div>

                {/* Icon */}
                <div style={{ width: 64, height: 64, borderRadius: 18, background: isHovered ? ic.bg : "#F8FAFF", border: `1.5px solid ${isHovered ? "transparent" : "#E8EEFF"}`, display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 24, transition: "all 0.3s", boxShadow: isHovered ? `0 8px 24px ${s.color}44` : "none" }}>
                  <span style={{ fontSize: 28 }}>{ic.emoji}</span>
                </div>

                {/* Tag */}
                <div style={{ display: "inline-block", background: `${s.color}14`, color: s.color, fontSize: 9.5, fontWeight: 900, letterSpacing: 2, textTransform: "uppercase", padding: "4px 12px", borderRadius: 50, marginBottom: 12, border: `1px solid ${s.color}22` }}>
                  {s.tag}
                </div>

                {/* Title */}
                <h3 style={{ fontWeight: 900, fontSize: "clamp(16px,2vw,20px)", color: "#0F172A", marginBottom: 12, lineHeight: 1.3, letterSpacing: -0.5 }}>
                  {s.title}
                </h3>

                {/* Description */}
                <p style={{ fontSize: 13.5, color: "#64748B", lineHeight: 1.8, marginBottom: 24, fontWeight: 400 }}>
                  {s.desc.substring(0, 90)}...
                </p>

                {/* Sub-services pills */}
                <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 24 }}>
                  {s.sub.slice(0, 3).map(sub => (
                    <span key={sub.title} style={{ fontSize: 10.5, fontWeight: 700, color: isHovered ? s.color : "#94A3B8", background: isHovered ? `${s.color}10` : "#F8FAFF", border: `1px solid ${isHovered ? `${s.color}22` : "#E8EEFF"}`, padding: "4px 10px", borderRadius: 50, transition: "all 0.3s" }}>
                      {sub.title.split(" ")[0]}
                    </span>
                  ))}
                  <span style={{ fontSize: 10.5, fontWeight: 700, color: "#94A3B8", background: "#F8FAFF", border: "1px solid #E8EEFF", padding: "4px 10px", borderRadius: 50 }}>
                    +{s.sub.length - 3} more
                  </span>
                </div>

                {/* CTA */}
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                  <span style={{ fontSize: 13.5, fontWeight: 800, color: isHovered ? s.color : "#94A3B8", transition: "color 0.3s" }}>
                    Explore Service
                  </span>
                  <div style={{ width: 36, height: 36, borderRadius: "50%", background: isHovered ? s.color : "#F1F5F9", display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.3s", transform: isHovered ? "translateX(4px)" : "none" }}>
                    <span style={{ fontSize: 14, color: isHovered ? "#fff" : "#94A3B8" }}>→</span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Bottom CTA */}
        <div style={{ textAlign: "center", marginTop: 56 }}>
          <p style={{ color: "#94A3B8", fontSize: 14, marginBottom: 16 }}>Not sure which service fits you?</p>
          <button
            className="btn-primary"
            style={{ fontSize: 15, padding: "14px 36px" }}
            onClick={() => window.open("https://wa.me/919869043500", "_blank")}
          >
            💬 Talk to Our Expert
          </button>
        </div>

      </div>
    </div>
  );
}